// Parse PR Payload → sprint_id, component, pr metadata
const body = $input.first().json.body ?? $input.first().json;

// Guard: only process merged PRs targeting main
const pr = body.pull_request;
const isMerged = body.action === 'closed' && pr?.merged === true;
const targetBranch = pr?.base?.ref ?? '';

if (!isMerged || targetBranch !== 'main') {
  return [{ json: { skip: true, reason: `Not a merged PR to main. action=${body.action} merged=${pr?.merged} base=${targetBranch}` } }];
}

const prNumber     = pr.number;
const prTitle      = pr.title ?? '';
const prBody       = pr.body ?? '';
const prUrl        = pr.html_url ?? '';
const commitSha    = pr.merge_commit_sha ?? '';
const prLabels     = (pr.labels ?? []).map(l => l.name);
const changedFiles = pr.changed_files ?? 0;

// Derive sprint_id from PR title or branch name
const sprintMatch = (prTitle + ' ' + (pr.head?.ref ?? '')).match(/[Ss]-(\d+)/);
const sprint_id   = sprintMatch ? `S-${sprintMatch[1]}` : 'S-UNKNOWN';

// Derive component from labels or title heuristic
const componentLabel = prLabels.find(l => l.toLowerCase().startsWith('component:'));
let component = 'General';
if (componentLabel) {
  component = componentLabel.replace(/^component:/i, '').trim();
} else {
  const compMatch = prTitle.match(/\[(.*?)\]/) || prTitle.match(/(Launchpad|Ops Tracker|Financial Bible|Prompt Architect|Compliance Matrix|Proposal Review|QA Center|Approvals Queue|KPI Strip|Pipeline)/i);
  if (compMatch) component = compMatch[1].trim();
}

// Derive doc_type
let doc_type = 'sprint_notes';
if (prLabels.some(l => /book.of.truths/i.test(l)) || /book.of.truths/i.test(prBody)) {
  doc_type = 'book_of_truths';
} else if (prLabels.some(l => /decision/i.test(l)) || /^decision:/im.test(prBody)) {
  doc_type = 'decision_log';
} else if (prLabels.some(l => /master.build/i.test(l)) || /master.build/i.test(prBody)) {
  doc_type = 'master_build_note';
}

return [{
  json: {
    skip: false,
    sprint_id,
    component,
    doc_type,
    workflow_name: 'GDA.doctrine.pr-merge-draft',
    pr_number:        prNumber,
    pr_title:         prTitle,
    pr_body:          prBody,
    source_pr_url:    prUrl,
    source_commit_sha: commitSha,
    pr_labels:        prLabels,
    changed_files:    changedFiles,
  }
}];

const d = $input.first().json;

const prBody  = d.pr_body ?? '';
const prTitle = d.pr_title ?? '';
const labels  = d.pr_labels ?? [];
const sprint  = d.sprint_id;
const comp    = d.component;
const docType = d.doc_type;

// safety_lane_impact
let safety_lane_impact = 'unknown';
const safetyLabel = labels.find(l => /^safety:/i.test(l));
if (safetyLabel) {
  safety_lane_impact = safetyLabel.replace(/^safety:/i, '').trim();
} else if (/\bapproval.required\b/i.test(prBody + prTitle)) {
  safety_lane_impact = 'approval-required';
} else if (/\bdry.run\b/i.test(prBody + prTitle)) {
  safety_lane_impact = 'dry-run';
} else if (/\bread.only\b/i.test(prBody + prTitle)) {
  safety_lane_impact = 'read-only';
} else if (/\btest.row\b/i.test(prBody + prTitle)) {
  safety_lane_impact = 'test-row';
} else if (/\bno safety\b|no.lane.change/i.test(prBody + prTitle)) {
  safety_lane_impact = 'none';
}

const current_live_state_md = `## Current Live State\n\n**Sprint:** ${sprint}  \n**Component:** ${comp}  \n**PR:** [#${d.pr_number}](${d.source_pr_url})  \n**Merged commit:** \`${d.source_commit_sha}\`  \n\n${prBody || '_No PR body provided._'}`;

const planned_state_md = `## Planned State\n\n_To be enriched by operator or subsequent automation. Source PR: [#${d.pr_number}](${d.source_pr_url})_`;

const recommended_next_state_md = `## Recommended Next State\n\n_Derived from PR merge. Review and update after smoke/QA checks pass._`;

const decision_md = docType === 'decision_log'
  ? `## Decision\n\n${prBody || '_No decision text in PR body._'}`
  : null;

const checks_required_json = [
  { check: 'ci_build_green',          required: true },
  { check: 'react_smoke_pass',         required: true },
  { check: 'qa_center_readonly_pass',  required: true },
  { check: 'qa_center_dryrun_pass',    required: safety_lane_impact !== 'read-only' },
  { check: 'master_build_guard_pass',  required: true },
  { check: 'frozen_workflows_intact',  required: true },
];

const rendered_markdown = [
  `# Doctrine Draft — ${sprint} / ${comp}`,
  ``,
  `**Doc type:** ${docType}  `,
  `**Status:** draft  `,
  `**Safety lane:** ${safety_lane_impact}  `,
  `**PR:** [#${d.pr_number}](${d.source_pr_url}) — ${prTitle}  `,
  `**Commit:** \`${d.source_commit_sha}\`  `,
  ``,
  current_live_state_md,
  ``,
  planned_state_md,
  ``,
  recommended_next_state_md,
  decision_md ? `\n${decision_md}` : '',
].join('\n');

const title = `${sprint} / ${comp} — ${prTitle}`.slice(0, 200);

return [{
  json: {
    ...d,
    title,
    safety_lane_impact,
    current_live_state_md,
    planned_state_md,
    recommended_next_state_md,
    decision_md,
    checks_required_json,
    rendered_markdown,
    status: 'draft',
    created_by: 'GDA.doctrine.pr-merge-draft',
    updated_by: 'GDA.doctrine.pr-merge-draft',
  }
}];
